        file.usages = [VendorUsageEntry(vendor: "claude", account: "new@b.com")]
        #expect(file.outagesByVendor[.claude]?.count == 1)
        #expect(file.usages.count == 1)
        #expect(file.usages[0].account == AccountEmail(rawValue: "new@b.com"))
    }
}

