    // MARK: - Lock error paths

    @Test("read returns empty file when lock times out")
    func lockTimeoutFallsBackToEmpty() async throws {
        let dir = makeTempDir()
        let filePath = "\(dir)/usages.json"
        let lockPath = filePath + ".lock"

        // Pre-create and hold an exclusive lock so the manager cannot acquire it
        let fd = Darwin.open(lockPath, O_CREAT | O_RDWR, 0o644)
        #expect(fd >= 0)
        flock(fd, LOCK_EX)
        defer { flock(fd, LOCK_UN); Darwin.close(fd) }

        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let mgr = UsagesFileManager(filePath: filePath, logger: logger, lockTimeoutSeconds: 0.1)
        let result = await mgr.read()
        // Lock timed out — manager falls back to empty file
        #expect(result.usages.isEmpty)
    }

    @Test("read returns empty file when lock file cannot be opened")
    func cannotOpenLockFileFallsBackToEmpty() async throws {
        let dir = makeTempDir()
        // Make the lock path a directory so Darwin.open returns -1
        let filePath = "\(dir)/usages.json"
        let lockPath = filePath + ".lock"
        try FileManager.default.createDirectory(atPath: lockPath, withIntermediateDirectories: false)
        defer { try? FileManager.default.removeItem(atPath: lockPath) }

        let logger = FileLogger(filePath: "\(dir)/test.log", minLevel: .debug)
        let mgr = UsagesFileManager(filePath: filePath, logger: logger)
        let result = await mgr.read()
        // Darwin.open failed — manager falls back to empty file
        #expect(result.usages.isEmpty)
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Test doubles

/// A mock FileWatching that lets tests push arbitrary Data payloads.
/// Implemented as a class so `changes()` can hand out a fresh AsyncStream on each
/// call — required for start/stop/start lifecycle tests where the previous iteration
/// is cancelled before a new watchTask begins consuming again.
// swiftlint:disable:next w4_unchecked_sendable — all test access is single-threaded on the main actor; AsyncStream.Continuation is Sendable
final class MockFileWatcher: FileWatching, @unchecked Sendable {
    private var continuation: AsyncStream<Data>.Continuation?
    /// Buffers sends that arrive before the watch task calls changes(), or after a
    /// cancelled previous cycle. Flushed immediately when changes() is called.
    private var pendingData: [Data] = []

    func changes() -> AsyncStream<Data> {
        // Finish the previous stream (if any) before creating a new one.
        // This prevents a stale task from consuming the new continuation's yields.
        continuation?.finish()
        var cont: AsyncStream<Data>.Continuation!
        let stream = AsyncStream<Data> { cont = $0 }
        continuation = cont
        // Flush sends that arrived before this call (e.g. test called send() before
        // the watch task had a chance to call changes()).
        for data in pendingData { cont.yield(data) }
        pendingData.removeAll()
        return stream
    }

    func send(_ data: Data) {
        guard let cont = continuation else {
            pendingData.append(data)
            return
        }
        // .terminated means the previous cycle's consuming task was cancelled;
        // buffer the data so the next changes() call can deliver it.
        if case .terminated = cont.yield(data) {
            continuation = nil
            pendingData.append(data)
        }
    }

    func finish() { continuation?.finish() }
}

/// A clock fixed at a given date, for deterministic remaining-time formatting.
struct FixedClock: ClockProvider {
    let date: Date
    init(_ date: Date) { self.date = date }
    func now() -> Date { date }
}

/// A clock whose date can be advanced between test steps to simulate time passing.
/// nonisolated(unsafe) — tests drive date changes from @MainActor, single-threaded; no concurrent writes.
@MainActor
final class MutableClock: ClockProvider {
    nonisolated(unsafe) var date: Date
    init(_ date: Date) { self.date = date }
    nonisolated func now() -> Date { date }
}

// MARK: - Helpers

private func makeUsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = []
) throws -> Data {
    let entry: [String: Any] = [
        "vendor": vendor,
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    let root: [String: Any] = ["usages": [entry]]
    return try JSONSerialization.data(withJSONObject: root)
}

/// Creates a v2 JSON payload with optional outages for a vendor.
private func makeV2UsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = [],
    outages: [[String: Any]] = []
) throws -> Data {
    let accountEntry: [String: Any] = [
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    var vendorSection: [String: Any] = ["accounts": [accountEntry]]
    if !outages.isEmpty {
        vendorSection["outages"] = outages
    }
    let root: [String: Any] = [
        "schemaVersion": 2,
        "vendors": [vendor: vendorSection],
    ]
    return try JSONSerialization.data(withJSONObject: root)
}

private func outageJSON(
    id: String = "inc-1",
    title: String = "API issues",
    severity: String = "major",
    affectedComponents: [String] = []
) -> [String: Any] {
    var json: [String: Any] = ["id": id, "title": title, "severity": severity]
    if !affectedComponents.isEmpty {
        json["affectedComponents"] = affectedComponents
    }
    return json
}

private func timeWindowMetric(
    name: String = "5h sessions (all models)",
    resetAt: String = "2026-04-17T15:00:00Z",
    windowDurationMinutes: Int = 300,
    usagePercent: Int = 42
) -> [String: Any] {
    [
        "type": "time-window",
        "name": name,
        "resetAt": resetAt,
        "windowDurationMinutes": windowDurationMinutes,
        "usagePercent": usagePercent,
    ]
}

private func payAsYouGoMetric(
    name: String = "monthly",
    currentAmount: Double = 12.50,
    currency: String = "USD"
) -> [String: Any] {
    [
        "type": "pay-as-you-go",
        "name": name,
        "currentAmount": currentAmount,
        "currency": currency,
    ]
}

